parameters.jsCode:
const ctx = $('Preparar Prompt de Filtro').item.json;
const aiResponse = $input.first().json;

const message = aiResponse.choices?.[0]?.message;
const toolCalls = message?.tool_calls;

let califica = null;
let siguientePaso = 'continuar_filtro';
let razon = '';
let replyText = message?.content || '';

if (toolCalls && toolCalls.length > 0) {
  try {
    const args = JSON.parse(toolCalls[0].function.arguments);
    califica = args.califica;
    siguientePaso = args.siguiente_paso || 'continuar_filtro';
    razon = args.razon || '';

    if (califica === true) {
      replyText = `Gracias por la información. Basado en lo que me comentas, creo que podemos ayudarte. Te voy a mostrar la disponibilidad para que puedas agendar una consulta con nosotros.`;
    } else if (califica === false) {
      replyText = `Agradezco que te hayas comunicado con nosotros. Después de analizar tu situación, en este momento los servicios del despacho no se ajustan completamente a lo que necesitas.`;
    }
  } catch(e) {
    siguientePaso = 'continuar_filtro';
  }
}

// Calcular tokens usados (aproximado)
const tokensUsados = aiResponse.usage?.total_tokens || 0;
const nuevosTokensLead = (ctx.tokens_consumidos_lead || 0) + tokensUsados;
const nuevosMensajes = (ctx.mensajes_ia_sesion || 0) + 1;

// Verificar si debe bloquearse (límites)
const limiteMensajes = ctx.limite_mensajes_sesion || 10;
const limiteTokensLead = ctx.limite_tokens_lead || 5000;
const debeBloquearse = nuevosMensajes >= limiteMensajes || nuevosTokensLead >= limiteTokensLead;

return [{
  json: {
    ...ctx,
    califica_ia: califica,
    siguiente_paso_ia: siguientePaso,
    razon_ia: razon,
    reply_text: replyText,
    tokens_usados: tokensUsados,
    nuevos_tokens_lead: nuevosTokensLead,
    nuevos_mensajes: nuevosMensajes,
    debe_bloquearse: debeBloquearse
  }
}];
